// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

// =====================================================
// NOVO TRECHO → Conta mensagens seguidas do agente
// =====================================================
let qtd_mensagens_sem_resposta = 0;

for (let i = historico.length - 1; i >= 0; i--) {
  if (historico[i].autor === "Agente") {
    qtd_mensagens_sem_resposta++;
  } else {
    break; // usuário falou → reset
  }
}
// =====================================================

return [
  {
    json: {
      historico_conversa: historico,
      qtd_mensagens_sem_resposta
    }
  }
];

return items.map(item => {
  let raw = item.json.output || "";
  let cleaned = raw;

  // 1. Remove blocos de código tipo ```json ... ```
  cleaned = cleaned.replace(/```json/gi, "");
  cleaned = cleaned.replace(/```/g, "");
  cleaned = cleaned.trim();

  let respostaIA = {};

  // 2. Parse seguro
  try {
    respostaIA = JSON.parse(cleaned);
  } catch (e) {
    respostaIA = {
      template: "erro",
      var_1: item.json.name || "",
      telefone: item.json.telefone || "",
    };
  }

  // 3. Mapa de templates oficiais (Cobrança — IA Luana)
  const templates = {
    lembrar_pagamento_amigavel:
      "Oi *{{1}}*! Vi aqui que a inscrição não rodou. O link não abriu ou foi só correria aí mesmo?",

    reforco_pagamento_duvida:
      "Tudo bem, *{{1}}*? Vi que sua inscrição ainda não foi confirmada. Ficou alguma dúvida?",

    acompanhamento_processo:
      "Opa *{{1}}*. Tô de olho aqui e vi que parou na etapa final. Falta alguma informação pra fechar ou tá tranquilo?",

    reforco_valor_investimento:
      "Fala *{{1}}*! Só pra não deixar passar esse conteúdo muda o jogo, não queria que você perdesse. Bora garantir?",

    gentle_followup_pagamento:
      "Oi *{{1}}*! A sua inscrição ainda tá em aberto aqui. Se tiver alguma dúvida ou dificuldade, me chama que a gente resolve rápido.",

    reforco_presenca_turma:
      "Olá *{{1}}*! \n\n A turma tá quase fechada e senti sua falta na lista. Posso te ajudar com algum detalhe pra você não ficar de fora?",

    reforco_continuidade:
      "E aí *{{1}}*! Bora finalizar essa inscrição? \n\n Falta só a confirmação do pagamento pra você entrar na turma.",

    urgencia_suave_vaga:
      "Tudo certo, *{{1}}*? Tô segurando sua vaga, mas as inscrições continuam rodando. Quer ajuda pra fechar logo?",

    reforco_final_amigavel:
      "Oi *{{1}}*. Não quero ser chata, rsrs. É só pra você não perder o prazo mesmo. Tá dando certo para finalizar a inscrição?",

    ultimo_followup_pagamento:
      "Oi *{{1}}*. Conseguiu finalizar sua inscrição? Se tiver desistido, me avisa que eu libero a vaga pra fila de espera, sem problemas.",

    despedida_encerramento_pagamento:
      "Oi *{{1}}*. Como não tive retorno, vou encerrar por aqui pra não te incomodar. Se quiser voltar depois, é só chamar!"
  };

  // 4. Seleciona template e faz substituição das variáveis
  const templateName = respostaIA.template;
  const textoTemplate = templates[templateName] || "Template não encontrado.";

  const mensagemFinal = textoTemplate
    .replace("{{1}}", respostaIA.var_1 || "");

  // 5. Retorno final do node
  return {
    json: {
      ...respostaIA,
      mensagem_template: mensagemFinal,
    },
  };
});

const templates = {
  lembrar_pagamento_amigavel:
    "Oi *{{1}}*! Tudo bem?  \n\nNotei que sua inscrição ainda está pendente e quis confirmar se deu tudo certo por aí. \nSe precisar de alguma ajuda pra concluir, posso te orientar rapidinho!",

  reforco_pagamento_duvida:
    "Oi *{{1}}*! Tudo tranquilo? \n\nPassando só pra lembrar da sua inscrição — às vezes o processo pode travar em algum detalhe, e posso te ajudar a resolver agora mesmo se quiser.",

  acompanhamento_processo:
    "Opa *{{1}}*, tudo bem? \n\nTô acompanhando seu cadastro e vi que o pagamento ainda não foi finalizado. \nTá tudo certo com o processo ou quer que eu te ajude a revisar juntos?",

  reforco_valor_investimento:
    "Oi *{{1}}*! Tudo bem? \n\nA sua inscrição garante acesso a um conteúdo que realmente faz diferença pra quem quer crescer no mercado. \nSe quiser, posso te ajudar a finalizar tudo hoje pra garantir sua vaga com tranquilidade",

  gentle_followup_pagamento:
    "Oi *{{1}}*! Tudo bem? \n\nSó passando pra lembrar que sua inscrição ainda está em aberto. \nSe precisar de ajuda pra concluir, me chama aqui — é rapidinho de resolver",

  reforco_presenca_turma:
    "Olá *{{1}}*, tudo bem? \n\nA turma está se organizando e percebi que o seu pagamento ainda não foi confirmado. \nPosso te ajudar pra que consiga garantir sua vaga junto com o grupo?",

  reforco_continuidade:
    "Oi *{{1}}*! Tudo bem? \n\nSó passando pra lembrar de concluir o pagamento da sua inscrição. \nAssim você já garante o acesso completo ao conteúdo e não perde o início das aulas!",

  urgencia_suave_vaga:
    "Oi *{{1}}*, tudo certo? \n\nAs vagas estão quase encerrando e ainda não identificamos seu pagamento. \nSe quiser, posso te ajudar agora mesmo pra garantir que tudo fique certinho.",

  reforco_final_amigavel:
    "Oi *{{1}}*! Tudo bem? \n\nVi que sua inscrição continua pendente e quis reforçar pra não deixar passar o prazo. \nQualquer detalhe que eu possa te ajudar a ajustar, é só me chamar",

  ultimo_followup_pagamento:
    "Oi *{{1}}*! Tudo bem? \n\nPassando pra confirmar se conseguiu concluir o pagamento da inscrição. \nTô por aqui pra te ajudar com o que for preciso pra finalizar tudo direitinho",

  despedida_encerramento_pagamento:
    "Oi *{{1}}*, tudo bem? \n\nComo não tivemos retorno nas últimas mensagens, vou encerrar nosso acompanhamento por aqui, combinado? \nSe precisar de ajuda mais pra frente, estarei por aqui pra te apoiar"
};

// --- PROCESSADOR ---
const entrada = items[0].json;
const textoTemplate = templates[entrada.template];

if (!textoTemplate) {
  return [{ json: { erro: "Template não encontrado" } }];
}

const possuiVar1 = textoTemplate.includes("{{1}}");

// monta estrutura da API do WhatsApp
const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefone),
  type: "template",
  template: {
    name: entrada.template,
    language: { code: "pt_BR" }
  }
};

if (possuiVar1) {
  body.template.components = [
    {
      type: "body",
      parameters: [
        { type: "text", text: entrada.var_1 }
      ]
    }
  ];
}

// RETORNO NO FORMATO EXATO QUE VOCÊ QUER
return [
  {
    json: {
      resultado: body
    }
  }
];

